const rfp = ($input.first().json?.data || $input.first().json) || {};
const emailData = $('Get a message')?.item?.json || {};

const senderEmail = emailData?.from?.value?.[0]?.address || 'manual-test@example.com';
const receivedDate = emailData?.date || new Date().toISOString();

function parseDeadline(str) {
  if (!str) return null;
  let d = new Date(str);
  if (!isNaN(d.getTime())) return d;
  const clean = str.replace(/\s+at\s+/i,' ').replace(/\s+(EST|CST|MST|PST|EDT|CDT|MDT|PDT)$/i,'');
  d = new Date(clean);
  if (!isNaN(d.getTime())) return d;
  const m = str.match(/([A-Za-z]+\s+\d{1,2},?\s+\d{4})/);
  if (m) { d = new Date(m[1]); if (!isNaN(d.getTime())) return d; }
  return null;
}

let daysRemaining = 'N/A';
const deadlineDate = parseDeadline(rfp.submissionDeadline);
if (deadlineDate) {
  const today = new Date(); today.setHours(0,0,0,0); deadlineDate.setHours(0,0,0,0);
  daysRemaining = Math.ceil((deadlineDate - today) / (1000*60*60*24));
}

let urgency = 'Normal';
if (typeof daysRemaining === 'number') {
  if (daysRemaining <= 0)  urgency = 'OVERDUE';
  else if (daysRemaining <= 7)  urgency = 'Urgent';
  else if (daysRemaining <= 14) urgency = 'High';
}

let budgetDisplay = 'Not specified';
const bMin = parseFloat(rfp.budgetMin) || 0;
const bMax = parseFloat(rfp.budgetMax) || 0;
if (bMin && bMax) budgetDisplay = `$${bMin.toLocaleString()} - $${bMax.toLocaleString()}`;
else if (bMax)    budgetDisplay = `Up to $${bMax.toLocaleString()}`;
else if (bMin)    budgetDisplay = `Minimum $${bMin.toLocaleString()}`;

const questionCount = rfp.questionsToAnswerList
  ? rfp.questionsToAnswerList.split(';').filter(q => q.trim()).length
  : 0;

return [{ json: {
  issuingOrganization:  rfp.issuingOrganization  || 'N/A',
  projectTitle:         rfp.projectTitle          || 'N/A',
  rfpNumber:            rfp.rfpNumber             || 'N/A',
  submissionDeadline:   rfp.submissionDeadline    || 'N/A',
  projectScope:         rfp.projectScope          || 'N/A',
  requirementsList:     rfp.requirementsList      || 'N/A',
  evaluationCriteriaList: rfp.evaluationCriteriaList || 'N/A',
  questionsToAnswerList: rfp.questionsToAnswerList || 'N/A',
  budgetMin:            bMin,
  budgetMax:            bMax,
  budgetDisplay,
  requiredCount:        parseInt(rfp.requiredCount)  || 0,
  preferredCount:       parseInt(rfp.preferredCount) || 0,
  totalRequirements:    (parseInt(rfp.requiredCount) || 0) + (parseInt(rfp.preferredCount) || 0),
  questionCount,
  daysRemaining,
  urgency,
  senderEmail,
  receivedDate,
  criteriaList:         rfp.evaluationCriteriaList || 'Not specified',
  processedAt: new Date().toISOString()
}}];

